// line_index.h - Line index for O(1) line lookups and virtualized rendering
//
// LineIndex caches line boundaries from a PieceTable, enabling O(1) lookups
// for line positions and visible range calculations. This is essential for
// efficient rendering of large files (100K+ lines).

#pragma once

#include <vector>
#include <cstddef>
#include <cstdint>

namespace CodeEditor {

// Forward declaration
class PieceTable;

// ============================================================================
// Line Index Data Structures
// ============================================================================

struct LineEntry {
    size_t byte_offset;     // Byte offset of line start in document
    uint32_t line_number;   // 1-indexed line number
    uint16_t piece_hint;    // Hint for faster piece lookup (reserved)
    uint16_t flags;         // Reserved for git status (Phase 13)
};

// ============================================================================
// LineIndex Class
// ============================================================================

class LineIndex {
public:
    LineIndex();
    ~LineIndex();

    // ========================================================================
    // Build & Update Operations
    // ========================================================================

    // Build index from PieceTable (full scan - O(n) where n = document length)
    // Called once on document load
    void build(const PieceTable* pt);

    // Clear the index
    void clear();

    // Incremental update after insert
    // byte_pos: position where insert occurred
    // bytes_inserted: number of bytes inserted
    // newline_offsets: array of byte positions (relative to byte_pos) where newlines occur
    //                  Example: inserting "A\nB\n" has offsets [1, 3] (the '\n' characters)
    // newlines_added: number of '\n' characters in inserted text (length of newline_offsets)
    void update_after_insert(size_t byte_pos, size_t bytes_inserted,
                             const size_t* newline_offsets, int newlines_added);

    // Incremental update after delete
    // byte_pos: position where delete started
    // bytes_deleted: number of bytes deleted
    // newlines_removed: number of '\n' characters in deleted text
    void update_after_delete(size_t byte_pos, size_t bytes_deleted, int newlines_removed);

    // ========================================================================
    // Line Lookups (O(1) by line number)
    // ========================================================================

    // Get entry for a line (1-indexed)
    // Returns nullptr if line_num is out of range
    const LineEntry* get_line(size_t line_num) const;

    // Get total number of lines
    size_t line_count() const { return total_lines_; }

    // Check if index is empty
    bool empty() const { return total_lines_ == 0; }

    // ========================================================================
    // Viewport Calculations (O(1) with fixed line height)
    // ========================================================================

    // Get first visible line number for given scroll position
    // Returns 1-indexed line number
    size_t first_visible_line(float scroll_y) const;

    // Get last visible line number for given scroll position and viewport height
    // Returns 1-indexed line number (may exceed line_count if viewport is larger)
    size_t last_visible_line(float scroll_y, float viewport_height) const;

    // Get number of lines that fit in viewport
    size_t visible_line_count(float viewport_height) const;

    // ========================================================================
    // Reverse Lookup (O(log n) binary search)
    // ========================================================================

    // Find line number containing byte offset
    // Returns 1-indexed line number
    size_t byte_to_line(size_t byte_offset) const;

    // ========================================================================
    // Configuration
    // ========================================================================

    // Set fixed line height (must be called before viewport calculations)
    void set_line_height(float height) { line_height_ = height; }
    float line_height() const { return line_height_; }

    // Get total content height (for scrollbar calculation)
    float total_content_height() const;

private:
    // Index storage
    std::vector<LineEntry> lines_;
    size_t total_lines_;

    // Line height for viewport calculations
    float line_height_;
};

} // namespace CodeEditor
